INSERT INTO `videos` VALUES (1,32034,'tv-series','Дейв Шаппелл: Нестримний','Дейв Шаппелл: Нестримний',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:18:37','2026-02-09 15:18:38',NULL,NULL,NULL,NULL,'2026-02-09 15:18:37',2025,NULL,'1080p','У цьому безкомпромісному спецвипуску Шаппелл, як завжди, не уникає гострих тем: він коментує політичний хаос навколо Трампа та Національної гвардії, свою суперечливу участь у комедійному фестивалі в Ер-Ріяді (згадуючи Джамаля Хашоггі та свободу слова), падіння Шона Комбса (Дідді), трансгендерні питання, а також смерть Чарлі Кірка. Перша половина — класичний стендап з швидкими жартами та спостереженнями за «світом, що з\'їхав з глузду». Але справжня родзинка — фінальний «клоузер»: 30-хвилинна епічна історія, що простягається від 1910 року (боксер Джек Джонсон та закон Манна) до сучасності, переплітаючи американську історію расизму, влади, знаменитостей (від Ніпсі Хасла до Стіві Вандера) та власний досвід Шаппелла.',NULL,'https://uakino.best/uploads/mini/poster/66/332c7cd8cf0cd4206e095bafdadb22.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(2,32585,'movie','Морлоки','Морлоки',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:18:40','2026-02-09 15:18:40',NULL,NULL,NULL,NULL,'2026-02-09 15:18:40',2011,NULL,'BD-Rip','Американські військові в секретній лабораторії розробляють експериментальну машину часу, щоб зазирнути в майбутнє та, можливо, дістати з нього передові технології. Під час тесту портал відкривається — але замість корисних винаходів з майбутнього в сьогодення проникають Морлоки — жахливі, агресивні, мутовані гуманоїдні істоти, які в романі Веллса були деградованими нащадками робітничого класу, що живуть під землею.Морлоки виявляються хижаками: вони швидко адаптуються, нападають зграями, використовують примітивну, але ефективну тактику і починають справжню різанину. Група вчених, військових та техніків опиняється в пастці в лабораторії та на прилеглих територіях. Їм необхідно вижити, знайти спосіб закрити портал і зупинити вторгнення, поки Морлоки не поширилися по всьому світу.',NULL,'https://uakino.best/uploads/mini/poster/cd/19f5a9820b62fa19ec7ce663151cd5.jpg','1 год 24 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(3,32584,'movie','Мій майбутній бойфренд','Мій майбутній бойфренд',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:18:42','2026-02-09 15:18:42',NULL,NULL,NULL,NULL,'2026-02-09 15:18:42',2011,NULL,'BD-Rip','У далекому 3127 році, в ідеально впорядкованому, але емоційно спустошеному світі, люди давно відмовилися від почуттів, вважаючи любов джерелом хаосу й страждань. Допитливий молодий чоловік під кодовим ім’ям P-A-X-497/341, або просто Пакс, порушує всі правила, коли знаходить роман письменниці Елізабет Барретт — книгу, що пробуджує в ньому інтерес до заборонених і майже забутих понять любові, пристрасті та близькості. Щоб знайти відповіді, Пакс вирушає у минуле, в 2011 рік, де людські емоції ще керують вчинками, а життя сповнене суперечностей і випадковостей. У світі газетних вигадок, щоденної метушні та щирих почуттів він знайомиться з самою Елізабет — журналісткою й новоспеченою романісткою, яка навіть не підозрює, що стала ключем до його подорожі крізь час.',NULL,'https://uakino.best/uploads/mini/poster/f6/f6a2e1f25f8aa01fa4c56ac1a0b435.jpg','1 год 13 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(4,32581,'movie','Звичайне серце','Звичайне серце',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:18:44','2026-02-09 15:18:44',NULL,NULL,NULL,NULL,'2026-02-09 15:18:44',2014,NULL,'1080p','Події відбуваються в Нью-Йорку на початку 1980-х років, коли в гей-спільноті починають масово з’являтися загадкові смерті від рідкісних хвороб (саркома Капоші, пневмоцистна пневмонія тощо). Головний герой — Нед Вікс, відкритий гей-активіст і письменник (фактично альтер-его Ларрі Крамера). Він стає одним із перших, хто б’є на сполох, намагаючись змусити владу, медиків і саму гей-спільноту визнати масштаб загрози.Нед разом із друзями та союзниками, включаючи лікаря, журналіста, адвокатів і активістів, створюють одну з перших організацій з боротьби зі СНІДом — Gay Men’s Health Crisis. Вони стикаються з тотальним ігноруванням з боку уряду Рейгана, гомофобією в суспільстві, цензурою в пресі, страхом і запереченням у самій спільноті.',NULL,'https://uakino.best/uploads/mini/poster/bc/b5a6df39d9fee7148dcde1a19b5890.jpg','2 год 12 хв',NULL,NULL,'18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(5,32580,'movie','Єдина','Єдина',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:18:46','2026-02-09 15:18:46',NULL,NULL,NULL,NULL,'2026-02-09 15:18:46',2011,NULL,'BD-Rip','Події відбуваються в сучасному Мангеттені. Головний герой, Деніел — успішний інвестиційний банкір з ідеальним життям: люблячі батьки, блискуча кар\'єра, гарна наречена Джен і весілля вже за місяць. Він здається втіленням американської мрії — привабливий, спортивний, впевнений у собі. Але все змінюється, коли Деніел випадково зустрічає старого знайомого з коледжу — харизматичного відкритого гея Томмі. Після вечора з алкоголем і розмовами між ними стається ніч пристрасті, яку Деніел спочатку сприймає як «одноразову помилку». Цей інцидент запускає ланцюжок подій: Деніел починає сумніватися в своїй сексуальній орієнтації, намагається повернутися до нормального життя з Джен, але Томмі закохується по-справжньому і не готовий відступати...',NULL,'https://uakino.best/uploads/mini/poster/13/63821e812c69cf34e489fc04c6d85a.jpg','1 год 29 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(6,32579,'movie','Полегла імперія','Полегла імперія',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:18:48','2026-02-09 15:18:48',NULL,NULL,NULL,NULL,'2026-02-09 15:18:48',2012,NULL,'1080p','У постапокаліптичному світі далекої планети, де людство виживає серед безжальних пусток і руїн колишньої цивілізації, самітній самурай Хірокін змушений знову взяти до рук меч, якого він колись прагнув позбавитись. Переслідуваний темним минулим і почуттям провини, він кидає виклик власній долі після смертельної сутички з жорстоким диктатором Ґріффіном та його елітною армією воїнів, намагаючись урятувати дружину й сина. Залишений помирати серед безкрайніх пісків, Хірокін дивом виживає і вирушає в небезпечну подорож, де кожен крок наближає його до неминучого вибору між особистою помстою та боротьбою за свободу пригнобленого народу. Озброєний лише самурайським клинком і власним кодексом честі, він вступає у війну, що змінить усе, і поступово розкриває шокуючу правду про долю своєї родини.',NULL,'https://uakino.best/uploads/mini/poster/a2/9a9ec063b7ee64042cc93ca5100021.jpg','1 год 45 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(7,26151,'movie','Пес-вампір','Пес-вампір',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:18:50','2026-02-09 15:18:50',NULL,NULL,NULL,NULL,'2026-02-09 15:18:50',2012,NULL,'1080p','Ейс був таким же, як і будь-яка інша нова дитина в школі, поки його дідусь з Трансильванії не помер у віці 96 років, і не надіслав йому свого собаку Фанга. Ейс незабаром дізнається, що Фанг — вампірський собака, і він навіть говорить англійською! Божевільна вчена доктор Вархол і її незграбний асистент Френк намагаються захопити Фанга і вкрасти його ДНК в надії розробити новітню технологію проти старіння, але на щастя для Ейса, вампірському собаці вдається залишатися на крок попереду своїх переслідувачів. На цьому шляху виникає міцна дружба, коли Ейс і Фанг виявляють, що разом вони непереможні.',NULL,'https://uakino.best/uploads/mini/poster/c1/4dd39f77938e2aa18421b8935f351c.jpg','1 год 31 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(8,25864,'movie','Сестри Марч святкують Різдво','Сестри Марч святкують Різдво',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:18:52','2026-02-09 15:18:53',NULL,NULL,NULL,NULL,'2026-02-09 15:18:52',2012,NULL,'1080p','Містер Лоуренс кидає виклик своєму синові Тедді та його друзям-підліткам Джону Бруку та Дену Слоану, щоб довести, що вони можуть належним чином залицятися до дівчат, яких вони люблять: сестер Джо, Мег, Бет і Емі Марч. Останні сповнені рішучості запобігти продажу свого занедбаного будинку їхніми батьками Робертом і Маргарет Марч, тому шукають способи знайти допомогу та зібрати гроші на ремонт. Можливо, до письменниці Джо залицяється Тедді, але іскри летять і з Маркусом Бером, молодшим редактором, чия підтримка може забезпечити її публікацію.',NULL,'https://uakino.best/uploads/mini/poster/c5/3eadc8a11373c7e9f0c5f15579343e.jpg','1 год 31 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(9,25590,'tv-series','Агент Гамільтон: В інтересах нації','Агент Гамільтон: В інтересах нації',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:18:56','2026-02-09 15:18:56',NULL,NULL,NULL,NULL,'2026-02-09 15:18:56',2012,NULL,'1080p','Офіцер шведської розвідки Карл Гамільтон зустрів жінку, з якою хоче почати нормальне життя. Але його звичайний ритм переривається, коли він зникає без пояснення причин на чотири місяці, щоб проникнути в міжнародну лігу, яка викрала вдосконалені артилерійські снаряди з наведенням GPS, експортовані шведською оборонною групою Nordfors. Коли прикриття Гамільтона розкривається на кордоні між Узбекистаном і Афганістаном, на Лігу раптово нападає група найманців у масках із невідомим клієнтом. Гамільтону вдається уникнути смертоносної атаки, але гранати, які він намагався вистежити, зникли. Невдовзі гранати використали під час нападу на сомалійського політика миру...',NULL,'https://uakino.best/uploads/mini/poster/53/ba46d6313f6f29521aa08f89ead181.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(10,25589,'tv-series','Агент Гамільтон: Викрадена','Агент Гамільтон: Викрадена',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:18:59','2026-02-09 15:18:59',NULL,NULL,NULL,NULL,'2026-02-09 15:18:59',2012,NULL,'1080p','Гамільтон і Муна насолоджуються шведською літньою відпусткою на архіпелазі. Їхнє кохання одне до одного зміцніло, але чи вистачить у них мужності взяти на себе зобов’язання зав’язати тривалі стосунки?Одного дня на материку викрадають доньку найкращого друга Гамільтона, після того як її мати дає необачні коментарі ЗМІ про мусульманські сепаратистські групи на Аравійському півострові. Її викрадачі вимагають високу ціну, як у вигляді грошей, так і політичних поступок. Гамільтона втягують у справу, цього разу як друга сім’ї. Шлях підказок веде до багатого шейха та напівзруйнованого форту в палаючій пустелі. Зв\'язки шейха з Аль-Каїдою виходять на перший план під час драматичної спроби порятунку, коли Гамільтон раптово виявляє небезпеку для свого життя.',NULL,'https://uakino.best/uploads/mini/poster/a3/0e01d6d05812f743064aa235277529.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(11,32578,'movie','Тиждень акул','Тиждень акул',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:01','2026-02-09 15:19:01',NULL,NULL,NULL,NULL,'2026-02-09 15:19:01',2012,NULL,'1080p','Події розгортаються на віддаленому приватному острові, який належить багатому, ексцентричному та психічно нестабільному чоловікові на ім’я Талбот. Він влаштовує для групи випадково зібраних людей жахливу гру на виживання під назвою «Тиждень акул». Правила прості й жорстокі: протягом семи днів учасники щодня змушені проходити нове випробування, пов’язане з акулами. Кожен день — нова небезпека, нова акула, нова пастка. Той, хто виживе до кінця тижня, отримає свободу… і, можливо, величезну суму грошей. Але ніхто по-справжньому не вірить, що переможець взагалі існуватиме.В центрі історії сильна, але травмована жінка, що намагається вирватися з цього кошмару. Інші учасники — строката компанія: від самовпевненого спортсмена до нервової дівчини, від цинічного бізнесмена до звичайного хлопця, який випадково опинився не в тому місці. Усі вони швидко розуміють, що Талбот не просто грається — він насолоджується їхнім страхом, стражданнями та відчаєм.',NULL,'https://uakino.best/uploads/mini/poster/bd/38bfd5084c329d65656edb4742b9fe.jpg','1 год 29 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(12,32577,'movie','Загін Беверлі Гіллз','Загін Беверлі Гіллз',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:03','2026-02-09 15:19:04',NULL,NULL,NULL,NULL,'2026-02-09 15:19:03',1989,NULL,'1080p','У розпал болісного розлучення домогосподарка з Беверлі Гіллз Філліс намагається повернути сенс власному життю, несподівано очоливши загін «Дівчата дикої природи», до якого входить її донька та ще кілька дуже різних дівчат із привілейованого, але далеко не безхмарного світу. Серед них — розбещена Тіффані, чия участь у гуртку залежить від хабарів батька, мрійлива Емілі, що змушена відмовлятися від активностей через фінансові проблеми родини, тривожна Тесса, травмована розлученням батьків, озлоблена Чіка, покинута увагою зайнятих дорослих, і Клер — колишня дитяча зірка, яка бачить у цьому загоні шанс пожити звичайним життям. Намагаючись поєднати дух скаутського руху з реаліями розкішного життя, Філліс влаштовує «кемпінг» у готелі Беверлі Гіллз, де дівчата заробляють значки не за виживання в дикій природі, а за освоєння матеріального світу. Така інтерпретація викликає лють суворої окружної лідерки Вельди, яка прагне розформувати загін і починає безжальну кампанію саботажу.',NULL,'https://uakino.best/uploads/mini/poster/33/839327107ba56529c6673fb3b54b39.jpg','1 год 45 хв',NULL,NULL,'12+',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(13,25807,'movie','Напад акул на Нью-Джерсі','Напад акул на Нью-Джерсі',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:05','2026-02-09 15:19:06',NULL,NULL,NULL,NULL,'2026-02-09 15:19:05',2012,NULL,'1080p','Неприємності оточують Сісайд-Гайтс, штат Нью-Джерсі, коли інтенсивні вібрації від буріння, що лунають з нового пляжного курорту, знову приваблюють зграю смертоносних акул, які жадають людського м\'яса. За цих обставин син шерифа, ТіСі, та його друзі, які мають дивовижну схожість з акторами фільму «Берег Джерсі» (2009), вирішують взяти справу в свої руки, щоб запобігти кривавій бійні, яка, ймовірно, має відбутися якраз Четвертого липня. Чи вдасться ТіСі та його команді засмаглих гвідо позбавити Джерсі-Шор від убивць-альбіносів-людожерів?',NULL,'https://uakino.best/uploads/mini/poster/05/4e9a18694fff08624818d4b3d400c9.jpg','1 год 27 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(14,25967,'movie','Після Люсії','Після Люсії',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:07','2026-02-09 15:19:08',NULL,NULL,NULL,NULL,'2026-02-09 15:19:07',2012,NULL,'1080p','Пам’ять про втрату коханої матері та дружини все ще свіжа й нестерпна. Пригнічений Роберто та його донька-підліток Алехандра тікають із прибережного Пуерто-Вальярта, щоб почати все заново в метушливому Мехіко. Але, незважаючи на те, що Роберто вже влаштувався на роботу шеф-кухарем, а Алехандра, здається, не має проблем з адаптацією у своїй новій школі, непередбачені проблеми призводять обох до напруженої ситуації, яка неминуче вирішиться втратою контролю. Зрештою, життя сповнене нових починань; однак, з іншого боку, зміна життя може бути дуже страшною, особливо коли ви втратили все.',NULL,'https://uakino.best/uploads/mini/poster/25/129255c3a181d9a7fd36f164148a6b.jpg','1 год 43 хв',NULL,NULL,'16',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(15,25863,'movie','Снігова людина','Снігова людина',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:09','2026-02-09 15:19:10',NULL,NULL,NULL,NULL,'2026-02-09 15:19:09',2012,NULL,'1080p','Дедвуд, Південна Дакота, на схилах гори Рашмор. Харлі Андерсон, цинічний організатор заходів, хотів би влаштувати тут же величезний концерт (серед музикантів якого — Еліс Купер у ролі самого себе), незважаючи на сумніви та протидію екологів, і перш за все свого колишнього партнера Саймона, Квінта. Але на цих схилах багато десятиліть тому жила істота, легендарний Бігфут. Прокинувшись після тривалого заціпеніння, істота починає вбивати всіх навколо. Жадібний Харлі пропонує вбити його, щоб врятувати концертний проєкт, а Саймон хоче врятувати його, тому що він останній представник свого роду. Існування чудернацької істоти починає приваблювати багатьох мисливців, які мають намір зловити його, щоб заробити гроші, але Бігфут завжди завдає набагато більше жертв, аж до того, що армія вирішує збити його своїм повітряним флотом.',NULL,'https://uakino.best/uploads/mini/poster/cd/a85aca622357e5216e343ef1e5deb4.jpg','1 год 29 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(16,32567,'movie','Червона Шапочка','Червона Шапочка',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:11','2026-02-09 15:19:12',NULL,NULL,NULL,NULL,'2026-02-09 15:19:11',2006,NULL,'BD-Rip','Фільм є дуже вільною, сучасною та грайливою інтерпретацією класичної казки про Червону Шапочку. ВІн побудований на незвичайній мета-структурі: усе відбувається в рамках розповіді, яку бабуся розповідає своїм двом онукам — хлопчику та дівчинці, які сидять удома. Дівчинка нудьгує і хоче швидше піти гуляти, тому постійно перебиває бабусю, вимагає змінити сюжет, додати щось цікавіше, зробити героїв крутішими чи смішнішими. Бабуся поступово дозволяє дітям «переписувати» казку в реальному часі, і саме ця дитяча творчість стає головною рушійною силою фільму.Головною героїнею стає сучасна Червона Шапочка — жвава, трохи вперта дівчинка на ім’я Ред (Червона), яка живе в маленькому містечку. Одного дня їй доручають віднести кошик із їжею хворій бабусі, що живе в лісі. Але цього разу дорогою вона зустрічає не просто хитрого вовка, а справжнього вовкулаку — істоту, яка вдень виглядає як звичайна людина, а вночі перетворюється на звіра. Вовк у цій версії — харизматичний, трохи нахабний і дуже музичний персонаж, який співає, танцює і намагається обдурити всіх навколо.',NULL,'https://uakino.best/uploads/mini/poster/62/8d7fb1bfbb5e140f6a387e10e9c3e4.jpg','1 год 22 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(17,27791,'tv-series','Коктейль','Коктейль',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:19:15','2026-02-09 15:19:15',NULL,NULL,NULL,NULL,'2026-02-09 15:19:15',2012,NULL,'1080p','Міра - двадцятитрирічна дівчина, яка приїхала в Лондон до свого чоловіка. Вона дуже довго чекала цієї зустрічі, але, як виявляється пізніше, чоловік зовсім не потребував її. Ба більше, він виганяє дівчину, залишивши її в незнайомому місті зовсім одну, без грошей і даху над головою. Незабаром Міра знайомиться з добродушною молодою дівчиною Веронікою, яка працює фотографом і живе в Лондоні абсолютно одна, в невеликій квартирі. Дізнавшись сумну історію Міри, Вероніка пропонує їй пожити у неї деякий час, на що та з радістю погоджується. У цей час до Лондона приїжджає молодий чоловік на ім\'я Гаутам, щоб відвідати свого дядька і як слід розважитися. На одній із дискотек він знайомиться з Веронікою, після чого завалюється до неї в квартиру на всю ніч...',NULL,'https://uakino.best/uploads/mini/poster/40/9bea4bd08fcaafaac3ba304190c5bf.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(18,32563,'movie','Елла та друзі','Елла та друзі',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:17','2026-02-09 15:19:17',NULL,NULL,NULL,NULL,'2026-02-09 15:19:17',2012,NULL,'1080p','Головною героїнею є другокласниця Елла — жвава, розумна і трохи вперта дівчинка, яка вчиться в маленькій сільській школі. У цій школі особлива атмосфера: маленький клас, дуже добрий і креативний учитель, багато свободи та справжньої дружби між учнями. Але одного дня діти дізнаються жахливу новину — їхню улюблену школу збираються закрити і знести, щоб на її місці побудувати... гоночний трек. Це здається повним абсурдом і несправедливістю.Елла та її найкращі друзі (весела і трохи божевільна компанія) вирішують не здаватися. Вони запускають справжню операцію порятунку школи: придумують хитрі плани, влаштовують маленькі пригоди, намагаються переконати дорослих і навіть влаштовують щось на кшталт великого змагання, щоб показати, наскільки насправді важлива їхня школа.',NULL,'https://uakino.best/uploads/mini/poster/31/a3448891bcff91d074564305d321eb.jpg','1 год 18 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(19,7591,'movie','Мадам Нобель','Мадам Нобель',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:19','2026-02-09 15:19:19',NULL,NULL,NULL,NULL,'2026-02-09 15:19:19',2014,NULL,'1080p','Берта Кінскі свого часу працювала помічницею Альфреда Нобеля. Їх спільна діяльність поступово переросла в любовні відносини. Засновник знаменитої на весь світ премії, а в той час відомий винахідник і мандрівник, був закоханий в цю чарівну жінку. Якщо будете дивитися фільм онлайн, то дізнаєтеся, що Берта Кінскі в результаті відкинула залицяння відомого вченого і віддала перевагу барону Артуру фон Зуттнер - чоловікові, який був молодший героїні фільму Мадам Нобель (2015) на сім років. Разом зі своїм коханцем Берта Кінскі їде на Кавказ і потрапляє в саму гущу російсько-турецької війни, події якої вражають жінку настільки, що вона в листах до Нобелю розповідає про всі її жахи.',NULL,'https://uakino.best/uploads/mini/poster/7d/7600f95387c2f091713174b5d82e4d.jpg','88 хвилин (01:28)',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(20,26396,'movie','Запаморочливі фантазії Чарлі Свона ІІI','Запаморочливі фантазії Чарлі Свона ІІI',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:21','2026-02-09 15:19:21',NULL,NULL,NULL,NULL,'2026-02-09 15:19:21',2012,NULL,'1080p','Чарлі Свон-третій досяг у житті всього, про що мріяв. Він володіє дизайнерським агентством, яке стало відомим у всьому світі. Чоловік живе багатим і розкішним життям: у нього багато впливових і знаменитих друзів, він має стосунки з найкрасивішими дівчатами світу. Однак, незважаючи на те, що Чарлі справжній ловелас, він все ж зустрічає ту єдину дівчину, яка підкорила його серце. Але їм не судилося довго бути разом. Після того, як Івона знайшла в шафі Чарлі колекцію фотографій його колишніх, вона вирішила залишити його, аргументуючи це тим, що не бажає колись стати однією з них. Серце Чарлі розбите, і він не знає, що йому тепер робити. Спасінням для нього стають фантазії, в яких він бореться за свою кохану. Чи зможе головний герой повернути даму свого серця в реальному житті?',NULL,'https://uakino.best/uploads/mini/poster/ad/867c5256967965c6a29d08811f8d40.jpg','1 год 26 хв',NULL,NULL,'16',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(21,27922,'movie','Наїзниці та янголи','Наїзниці та янголи',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:23','2026-02-09 15:19:24',NULL,NULL,NULL,NULL,'2026-02-09 15:19:23',2012,NULL,'1080p','12-річна Айда Клейтон живе разом зі своєю матір’ю-одиначкою Елейн в урбанізованій частині Оклахоми, але її літні дні минають у нудьзі й без жодних розваг. Щоб якось урізноманітнити своє дозвілля, вона починає потайки відвідувати родео. Айда ніколи не знала свого батька — чоловіка на ім’я Волкер, про якого Елейн категорично відмовляється говорити. Це одна з причин, чому мати не схвалює захоплення доньки родео.Коли Айда отримує можливість вирушити в турне Америкою разом із «Солодкими серцями родео» — групою дівчат, які виступають на шоу родео, вона приймає цю пропозицію. Після кількох подій Елейн усе ж дає згоду. Айда швидко знаходить спільну мову з менеджером гурту Терренсом Паркером і його донькою Ребеккою. Разом із «Солодкими серцями» Айда вирушає на пошуки свого батька.',NULL,'https://uakino.best/uploads/mini/poster/de/18082dd2129cbb18437c434cdc012d.jpg','1 год 32 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(22,26955,'movie','Кохання 911','Кохання 911',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:26','2026-02-09 15:19:26',NULL,NULL,NULL,NULL,'2026-02-09 15:19:26',2012,NULL,'1080p','Кінець одного - завжди початок чогось іншого. У центрі сюжету - молодий пожежник Кан-Іль. За час своєї роботи він врятував безліч людських життів від бурхливого вогню. Але не зміг врятувати кохану дружину. Ця трагічна подія стала величезним ударом для чоловіка. Він зламався внутрішньо і тепер навмисно грає зі смертю, втративши будь-який страх. В той же час, геніальна дівчина, лікарка Ко Мі Су, з необережності зробила лікарську помилку, після чого її позбавили ліцензії на кілька років. Тепер вона працює волонтером-фельдшером і щодня бачить симпатичного Кан-Іля. Дівчина закохується в нього, але чи зможе вона допомогти чоловікові впоратися з його психологічною травмою?',NULL,'https://uakino.best/uploads/mini/poster/10/8f937edd04874462813ff18cb71b19.jpg','2 год 00 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(23,27802,'movie','Полонянка','Полонянка',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:28','2026-02-09 15:19:28',NULL,NULL,NULL,NULL,'2026-02-09 15:19:28',2012,NULL,'1080p','Адіб Абдель-Карім був офіцером сирійських збройних сил до того, як його затаврували як зрадника і він був змушений втекти до Канади. Маючи дружину, двох доньок і постійну роботу в Торонто, Адіб впевнений, що залишив своє минуле позаду. Доти, доки не дізнається, що його старша донька Муна зникла в Дамаску після того, як таємно поїхала до Сирії під час виконання завдання в Греції. Через 20 років після втечі з Сирії Адіб змушений повернутися, щоб врятувати доньку від корумпованих урядових агентів, які безпідставно утримують її в полоні за звинуваченням у шпигунстві. Там він об\'єднується зі своєю колишньою нареченою Фатімою та канадським дипломатом Полом, щоб знайти доньку, переховуючись від колишніх колег і таємної поліції.',NULL,'https://uakino.best/uploads/mini/poster/38/5269ff6fa8176427e71663d0c8fbfe.png','1 год 33 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(24,26797,'movie','Створення леді','Створення леді',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:30','2026-02-09 15:19:30',NULL,NULL,NULL,NULL,'2026-02-09 15:19:30',2012,NULL,'1080p','1901 рік. Бідна, але кмітлива Емілі Фокс Сетон приймає пропозицію руки і серця від старшого лорда Джеймса Уолдерхерста, вдовця, якого змусила забезпечити спадкоємця його горда тітка Марія, роботодавець Емілі. Насправді це угода для обох - у випадку Джеймса, щоб зупинити передачу сімейного дому двоюрідному брату, Алеку Осборну, та його англо-індійській дружині Хестері. Незабаром між молодими людьми виникає щира прихильність, але Джеймса відправляють до Індії з його полком. В цей час Осборни приїжджають до Емілі, стверджуючи, що Джеймс надіслав їх, щоб піклуватися про неї. Насправді ж вони збрехали, і тривожні перепади настрою Алека, викликані хворобою, загрожують вагітності Емілі. Незабаром Емілі усвідомлює, що ця пара задумала щось недобре...',NULL,'https://uakino.best/uploads/mini/poster/1e/ae1dbf550f4d0cbc77128b999b6b0f.jpg','1 год 35 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(25,27883,'movie','Сліпий','Сліпий',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:32','2026-02-09 15:19:32',NULL,NULL,NULL,NULL,'2026-02-09 15:19:32',2012,NULL,'1080p','У Парижі виявлено жорстоко вбиту жінку у власній квартирі. Немає слідів зламу чи свідків — злочин здається ідеальним. Розслідування доручено командиру Лассалю, досвідченому, але самотньому поліцейському, який не може оговтатися після смерті дружини. Коли стаються інші подібні вбивства, Лассаль звертає увагу на Габріеля Нарвіка, сліпого майстра з налаштування піаніно. Хоча Нарвік має переконливе алібі, і його сліпота викликає сумніви щодо його причетності, між двома чоловіками розгортається напружене психологічне протистояння, схоже на шахову партію.',NULL,'https://uakino.best/uploads/mini/poster/ea/dd7dc3a169a6aefb1690b5ba22df68.jpg','1 год 34 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(26,27228,'movie','Острів смерті','Острів смерті',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:34','2026-02-09 15:19:34',NULL,NULL,NULL,NULL,'2026-02-09 15:19:34',2012,NULL,'1080p','Сара запрошує своїх друзів дитинства Лу та Еббі повернутися на острів, де вони разом відпочивали в юності, сподіваючись зібрати групу, яку життя тепер розділило. Але на острові вони зустрічають Генрі, Дерека та Алекса, трьох колишніх солдатів і мисливців. Обидві групи знайомі і є друзями, але атмосфера стає напруженою після того, як троє чоловіків розповідають про принизливий спосіб, яким армія звільнила їх після служби на Близькому Сході. Еббі, яка зацікавлена в Генрі, йде на прогулянку з ним, і вони врешті-решт цілуються. Генрі стає більш наполегливим з Еббі, яка відмовляється від нього і бореться за свою свободу, але Генрі, агресивний, починає її ґвалтувати. У своїй безнадійній спробі втекти Еббі випадково вбиває Генрі. У люті Дерек і Алекс починають переслідувати трьох жінок.',NULL,'https://uakino.best/uploads/mini/poster/e7/312b4c1d5c479cb6ca40bf93ed6022.png','1 год 23 хв',NULL,NULL,'18',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(27,11477,'tv-series','Імітатор','Імітатор',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:19:38','2026-02-09 15:19:38',NULL,NULL,NULL,NULL,'2026-02-09 15:19:38',1995,NULL,'1080p','Дія розвивається в Сан-Франциско. Кримінальний психолог Хелен Хадсон ледь не загинула під час суду, коли серійний маніяк Деріл спробував її вбити. Через трагічний інцидент у головної героїні розвинулась агарофобія, і тепер вона живе самітницьким життям зі своїм другом Енді, а її єдина можливість зв\'язатися із зовнішнім світом - комп\'ютер. Незабаром черговий серійний вбивця, що імітує відомих психопатів, починає погрожувати Хелен онлайн. Заручившись підтримкою поліцейського Холлі Хантера, жінка намагається ідентифікувати небезпечного маніяка ...',NULL,'https://uakino.best/uploads/mini/poster/de/82a7f1152ba27ced0c0d56d43461e8.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(28,27224,'movie','Супер циклон','Супер циклон',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:39','2026-02-09 15:19:40',NULL,NULL,NULL,NULL,'2026-02-09 15:19:39',2012,NULL,'1080p','Нафтовики, які займаються розробкою морського шельфу, помилково приступили до бурових робіт на місці близькому до ядра землі, що порушило геомагнітне поле. Все це призвело до жахливої загрози виникнення гігантського циклону, який може просто стерти з землі все східне узбережжя США. Двоє безстрашних людей, дізнавшись про це, об\'єднують всі свої сили і професіоналізм, для того щоб зупинити небезпеку, що насувається. Вчений-метеоролог і фахівець з буріння, розробляють досить незвичайний план, який, за їхніми словами, може запобігти стихії і врятувати життя сотні тисяч людей. Але вони не можуть приступити до дій, поки не переконають президента в необхідності невідкладних дій...',NULL,'https://uakino.best/uploads/mini/poster/a6/44914d97871f1cf49c407d915067bb.jpg','1 год 29 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(29,32554,'movie','Миш\'як і старі мережива','Миш\'як і старі мережива',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:41','2026-02-09 15:19:42',NULL,NULL,NULL,NULL,'2026-02-09 15:19:41',1944,NULL,'1080p','Події відбуваються в Брукліні, у старому будинку Брюстера, саме на Гелловін. Мортімер Брюстер — відомий критик, який роками писав статті та книги про те, що шлюб — це «застарілий забобон» і «кінець свободи». Але раптом він закохується в сусідку Елейн і таємно одружується з нею саме в день Гелловіну. Після церемонії він приводить молоду дружину додому, щоб познайомити з двома милими, доброзичливими тітками — Еббі та Мартою. Вони здаються ідеальними старенькими леді: печуть пироги, варять бузинове вино, допомагають самотнім людям...Але неочікувано Мортімер виявляє жахливу сімейну таємницю: тітки вбивають самотніх стареньких чоловіків, які приходять до них на ночівлю. Вони пригощають їх «вином» з домішкою миш\'яку, стрихніну та ціаністого калію — і роблять це як акт милосердя, щоб звільнити від страждань самотності. Ситуація ускладнюється ще більше, коли повертається давно зниклий брат Джонатан — божевільний маніяк із новим обличчям, який виглядає як Борис Карлофф, і його супутник — лікар Ейнштейн. А ще є третій брат Тедді, який думає, що він президент Теодор Рузвельт і копає Панамський канал... у підвалі.',NULL,'https://uakino.best/uploads/mini/poster/0c/a247df1a3f4b46936d885d0e9da6b7.jpg','1 год 58 хв',NULL,NULL,'12',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(30,32553,'movie','Гарбузоголовий','Гарбузоголовий',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:43','2026-02-09 15:19:44',NULL,NULL,NULL,NULL,'2026-02-09 15:19:43',2025,NULL,'HD 720p','Переїзд до Редгейвена мав стати для Кессі та її синів шансом почати все спочатку після важкої втрати. Але нове життя руйнується, коли старший син Фінн безслідно зникає. Найстрашніше полягає в тому, що дорослі навколо поступово забувають про його існування, ніби хлопчик був лише вигадкою. Тільки Сем продовжує пам\'ятати брата і відчуває, як реальність навколо нього спотворюється. Він розуміє, що часу залишається все менше, і якщо він зупиниться, Фінн зникне остаточно. У спробі знайти відповіді Сем чіпляється за будь-які зачіпки, поки спогади ще живі. Його шлях стає боротьбою з чимось незрозумілим, де ціна зволікання може виявитися занадто високою.',NULL,'https://uakino.best/uploads/mini/poster/0d/3322f0a32114bc518bcbfdb5fcbcc4.jpg','1 год 31 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(31,27231,'movie','В ритмі беззаконня','В ритмі беззаконня',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:46','2026-02-09 15:19:46',NULL,NULL,NULL,NULL,'2026-02-09 15:19:46',2012,NULL,'1080p','Одного разу, вкотре посварившись з матір\'ю та її новим обранцем, Елай вирішив покинути рідний дім і став бандитом. Разом зі своїми друзями наш герой став членом молодіжної банди, яка займалася дрібними злочинами та іншими подібними справами. Інша героїня фільму, обдарована дівчина Анабель, прагне вийти з тіні матері Анастейші Лі та розпочати свою співацьку кар\'єру. Ще раз, безрезультатно поговоривши, дочка з матір\'ю вирушили на концерт, на якому мали співати дуетом. Саме на цьому концерті наш герой познайомився з Анабель, і незабаром їхні стосунки стали близькими. Вони обоє люблять музику і одне одного. Елай хоче покінчити з кримінальними справами і все своє життя присвятити своїй коханій дівчині та музиці.',NULL,'https://uakino.best/uploads/mini/poster/62/813063a04f128a2018989b8b7f5ef3.jpg','1 год 25 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(32,32548,'movie','Пробуджені / Ми ховаємо мерців','Пробуджені / Ми ховаємо мерців',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:48','2026-02-09 15:19:48',NULL,NULL,NULL,NULL,'2026-02-09 15:19:48',2024,NULL,'1080p','Після випадкового застосування експериментальної зброї на борту американського військового корабля з карти зникає Гобарт, а всю Тасманію затягує густий сірий дим, що приховує масштаби катастрофи. Світові ЗМІ безупинно транслюють тривожні новини, міжнародна напруга зростає, а прем’єр-міністр Австралії у люті вимагає пояснень від США. На острів стікаються військові та волонтери, і портове місто Девонпорт переходить під повний контроль австралійських збройних сил, де кожного прибулого піддають жорстким перевіркам. Серед добровольців — американська фізіотерапевтка Ава, яка зголошується допомагати у зборі численних тіл загиблих на півночі Тасманії, ще не підозрюючи, з чим насправді доведеться зіткнутися. Згодом стає зрозуміло, що дія нової зброї виходить за межі звичного розуміння смерті: у деяких тіл фіксують дивні «ознаки життя», ніби мозок змушує мертві оболонки підводитися й боротися, перетворюючи зону катастрофи на смертельно небезпечний простір. Для Ави трагедія набуває особистого характеру, адже її чоловік Мітч перебував на розкішному курорті на півдні острова — саме тій частині Тасманії, яку військові повністю ізолювали й оголосили забороненою. Не вірячи офіційним заявам і розуміючи, що кожна хвилина може бути вирішальною, Ава вирішує втекти з-під контролю сил безпеки та перетнути острів у пошуках чоловіка, навіть знаючи, що всіх, хто повертається з півдня, військові розстрілюють без попередження. Єдиним її супутником стає Клей — поранений чоловік, за яким вона доглядала, і разом вони вирушають у подорож крізь заборонену територію, де стерта межа між життям і смертю.',NULL,'https://uakino.best/uploads/mini/poster/d8/373690007fdcf3c6cc64d9ef00f2db.jpg','1 год 34 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(33,32547,'movie','Чужа земля / Колонія','Чужа земля / Колонія',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:50','2026-02-09 15:19:50',NULL,NULL,NULL,NULL,'2026-02-09 15:19:50',2021,NULL,'1080p','У далекому майбутньому Земля стала практично непридатною для життя через кліматичну катастрофу, пандемії та війни. Еліта людства втекла на космічну колонію Kepler-209 (планета-супутник чи штучна станція). Але через кілька поколінь у колоністів виникає серйозна проблема — безпліддя через умови життя в штучному середовищі.Щоб перевірити, чи можна повернутися на Землю, відправляють експедицію. Головна героїня, астронавтка Блейк, після аварії опиняється одна на сильно зміненій Землі (майже вся планета затоплена, залишилися лише високогірні зони). Там вона зустрічає останніх вцілілих людей, які живуть у дуже примітивних умовах.',NULL,'https://uakino.best/uploads/mini/poster/f4/7eed0ea67a7b0612475d31bf347955.jpg','1 год 44 хв',NULL,NULL,'16',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(34,1513,'tv-series','Поліція Маямі: Відділ моралі','Поліція Маямі: Відділ моралі',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:19:54','2026-02-09 15:19:54',NULL,NULL,NULL,NULL,'2026-02-09 15:19:54',2006,NULL,'1080p','Все нове - це добре забуте старе. Фільм «Поліція Маямі: Відділ моралі» 2006 знятий за мотивами серіалу 80-років «Поліція Маямі». Глядачам так сподобалися головні герої телесеріалу, що автор і творець Майкл Манн вирішив повернути улюблених копів до життя, на цей раз на екрани кінотеатрів.Любов зла - цю істину поліцейський Сонні добре засвоїв після того, як невдало закохався в дівчину лідера одного з найбільших наркокартелів міста. Але ж спочатку ніщо не віщувало такого повороту подій. Пригоди копів почалися з того, що Сонні і його напарника Ріка старий друг попросив про послугу: якийсь час виконувати обов\'язки охоронців його дружини, адже, за словами товариша, жінка наражається на серйозну небезпеку. Незабаром стає зрозумілим, що дівчина не просто так виявилася метою таємничого злочинного угруповання: її чоловік та декілька інших агентів були співробітниками спецслужб і багато років працювали над справою великого картеля наркоторговців. Тепер їх прикриття розкрите, і загрозі піддалися всі, причетні до розслідування. Тепер напарникам доведеться продовжити справу товариша: впровадитися в мафіозний клан і розкрити їх темні справи.',NULL,'https://uakino.best/uploads/mini/poster/76/66aaf9a5170dc4dbbaf3a01ba51693.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(35,13873,'tv-series','Принц і я 2: Королівське весілля','Принц і я 2: Королівське весілля',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:19:57','2026-02-09 15:19:57',NULL,NULL,NULL,NULL,'2026-02-09 15:19:57',2006,NULL,'1080p','Нарешті історія про сучасну попелюшку Пейдж Морган підійшла до свого щасливого кінця! Її обранець – данський принц Едвард зробив їй офіційну пропозицію руки та серця. Тепер, на майбутню королеву Данії чекає подорож на батьківщину титулованого нареченого, де молоді повінчаються у великому кафедральному соборі.І все б добре, якби не горезвісні традиції. Перед самим весіллям наречений і наречена дізнаються про старовинний закон: спадкоємець данської корони може вступити на престол лише після весілля на особі благородної крові. Інакше він втратить трон...',NULL,'https://uakino.best/uploads/mini/poster/17/dfe1643c0d98139e1c74e8f0b2fe2d.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(36,32540,'movie','Кров машин','Кров машин',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:19:59','2026-02-09 15:19:59',NULL,NULL,NULL,NULL,'2026-02-09 15:19:59',2019,NULL,'1080p','Сюжет розгортається в ретро-футуристичному космосі в дусі 80-х: двоє космічних мисливців за нагородою — Васкан і Лаго — разом зі своєю корабельною ШІ \"Трейсі\" переслідують і збивають загадковий біопанк-корабель під назвою **Міма**. Після знищення з корабля народжується містична сутність — примарна молода жінка, яка є втіленням штучного інтелекту, що намагається звільнитися. Замість того, щоб просто померти, вона кидає виклик мисливцям, змушуючи їх гнатися за нею крізь космос. По дорозі вони потрапляють у сюрреалістичний, психоделічний кошмар: галактика наповнена голими жіночими тілами, що зливаються з машинами, ритуалами, кров\'ю, механічними богами та еротично-жорстокими видіннями.',NULL,'https://uakino.best/uploads/mini/poster/36/a4c45c753775825593b9dc3f2cc781.jpg','50 хв',NULL,NULL,'18+',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(37,32539,'movie','Справжня казка','Справжня казка',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:20:01','2026-02-09 15:20:01',NULL,NULL,NULL,NULL,'2026-02-09 15:20:01',2022,NULL,'1080p','Головна героїня на ім\'я Скай — вперта старшокласниця-підліток, яка не вірить у казки, романтику чи магію. Під час шкільного показу лялькового театру з класичними казковими мотивами Скай магічним чином переноситься в чарівне Королівство Селестія — яскравий світ, наповнений класичними казковими персонажами: принцами, принцесами, чарівними істотами, злими королевами та іншими знайомими архетипами. Там вона стикається з низкою химерних, часом комічних і абсурдних героїв, які змушують її переосмислити своє ставлення до життя, дружби, любові та власних страхів.',NULL,'https://uakino.best/uploads/mini/poster/ec/e246496de67b6241421991eea97652.jpg','1 год 12 хв',NULL,NULL,'12',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(38,32538,'tv-series','Кара','Кара',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:20:04','2026-02-09 15:20:04',NULL,NULL,NULL,NULL,'2026-02-09 15:20:04',2008,NULL,'1080p','Фільм розповідає про маленьке американське містечко, де після пожежі в старій церкві звільняється давній паразитичний демон, відомий як Кара. Ця істота була запечатана в стінах церкви ще півтора століття тому — приблизно з кінця XIX століття. Вона є паразитом, який переходить від людини до людини через рот чи інші отвори, повністю контролює тіло носія, змушує його жадібно їсти, блювати кров’ю, проявляти агресивну сексуальну поведінку та швидко вбивати жертву, після чого переходить до наступного господаря. Заражені люди стають схожими на зомбі-подібних істот, що швидко виснажуються й гинуть.Головні герої — молодий хлопець Скотт Міллер, який нещодавно вийшов з в’язниці і повернувся в рідне містечко, та його колишня дівчина Джессі. Їхні стосунки давно розвалилися, але саме вони виявляються єдиними, хто починає розуміти природу загрози. Скотт спочатку потрапляє під підозру в убивствах (його бачать біля мертвої колишньої дівчини, яка стала першою жертвою паразита в сучасному часі), а потім разом із Джессі намагається зупинити поширення Кари, перш ніж воно знищить усе населення.',NULL,'https://uakino.best/uploads/mini/poster/ff/fbbe64d97a53dbb8d5796248f1aeb8.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(39,32537,'tv-series','Останнє обличчя','Останнє обличчя',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:20:08','2026-02-09 15:20:08',NULL,NULL,NULL,NULL,'2026-02-09 15:20:08',2016,NULL,'1080p','Рен Пітерсон — лікарка й гуманітарна активістка, яка працює в Західній Африці, продовжуючи справу організації «Лікарі світу», заснованої багато років тому її батьком. Вона щиро віддана своїй місії та людям, яким допомагає, однак постійно живе в тіні батькової легенди, болісно порівнюючи власні досягнення з його спадщиною. У 2003 році Рен знайомиться з Мігелем — харизматичним хірургом, який так само присвятив себе роботі в найбідніших і зруйнованих війнами регіонах світу. Між ними швидко виникає сильне почуття, що дає надію на особисте щастя серед щоденного зіткнення з людськими трагедіями. Та крихка гармонія руйнується, коли Рен дізнається про минулий інтимний зв’язок Мігеля з її кузиною, і ця правда стає каталізатором недовіри, ревнощів і внутрішніх сумнівів.',NULL,'https://uakino.best/uploads/mini/poster/74/4f3ea6b7562aa45b405139f1d7ddbd.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(40,32536,'movie','Королева шахів','Королева шахів',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:20:10','2026-02-09 15:20:10',NULL,NULL,NULL,NULL,'2026-02-09 15:20:10',2026,NULL,'1080p','Документальний фільм розповідає захопливу історію життя Юдіт Полгар, найсильнішої шахістки в історії та єдиної жінки, яка по-справжньому змагалася на найвищому рівні серед чоловіків-гросмейстерів. Стрічка починається з дитинства Юдіт у комуністичній Угорщині 1970–80-х років, де її батько, психолог Ласло Полгар, вирішив довести, що генії не народжуються, а створюються. Він перетворив виховання трьох дочок — Сьюзен, Софії та Юдіт — на справжній експеримент: щоденні багатогодинні заняття шахами замість звичайної школи, вихідних і канікул. Усе життя сім’ї було підпорядковане шахам, і саме це дозволило Юдіт уже в шість років вигравати турніри проти дорослих чоловіків, а в 12 стати наймолодшою в історії шахісткою з рейтингом топ-рівня. Фільм показує архівні кадри її перших перемог, дитячі партії, сімейні відео та реакції оточення, яке не могло повірити, що маленька дівчинка з мисочкою на голові громить досвідчених гравців.',NULL,'https://uakino.best/uploads/mini/poster/3c/9a99ac77ef4644b9631385cc9d87c0.jpg','1 год 33 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(41,32588,'tv-series','Команда Фастфуд 1 сезон','Команда Фастфуд 1 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:20:15','2026-02-09 15:20:15',NULL,NULL,NULL,NULL,'2026-02-09 15:20:15',2000,NULL,'BD-Rip','Мультсеріал розповідає про абсурдні й сюрреалістичні пригоди трьох антропоморфних продуктів швидкого харчування, які живуть разом у тихому передмісті, але при цьому постійно занурюються в хаос. Егоїстичний і патологічно брехливий Мастер Шейк, розсудливий та інтелектуальний Фрайлок і наївний, мінливий за формою Мітвод утворюють дивну родину, чиє повсякденне життя перетворюється на низку безглуздих конфліктів, дивних експериментів і відверто ідіотських рішень. Їхнім постійним об’єктом роздратування стає сусід Карл — грубий, хтивий і голосний фанат спорту середнього віку, який мимоволі втягнутий у всі катастрофи, що виникають навколо. Майже в кожному епізоді герої стикаються з новими ворогами, серед яких особливе місце посідають Мунініти — двоє зарозумілих прибульців з Місяця, схильних до незаконних і руйнівних витівок. Світ мультсеріалу населений галереєю дивакуватих другорядних персонажів, які раз по раз повертаються з новими загрозами та ще більшим абсурдом, а події часто завершуються смертями, каліцтвами чи повним знищенням майна, що дивним чином без жодних пояснень скасовується в наступній серії. Це цинічна, хаотична й навмисно нелогічна комедія, яка висміює побут, попкультуру й саму структуру телевізійних шоу.',NULL,'https://uakino.best/uploads/mini/serial/92/7c31379fb04f56e82796d212fcc01a.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(42,32587,'movie','Коргот з Варварії','Коргот з Варварії',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:20:17','2026-02-09 15:20:17',NULL,NULL,NULL,NULL,'2026-02-09 15:20:17',2006,NULL,'BD-Rip','У жорстокому й безсоромно гротескному фентезійному світі, де маги підступні, шинкарі огрядні, злодії розбещені, а напівоголені діви постійно потребують порятунку, панує Кóрґот — найстрашніший і наймогутніший варвар, якого будь-коли знали ці землі. Цей анімаційний мультфільм для дорослих безжально пародіює жанр «меча і магії», перетворюючи класичні фентезійні кліше на вибухову суміш чорного гумору, насильства й абсурду. Коли черговий негідник встромляє сокиру Кóрґоту в плече, це не зупиняє його — лише погіршує настрій, який і без того далекий від доброзичливого. Озброєний грубою силою, непохитним стоїчним світоглядом і майже образливою кількістю везіння, Кóрґот прорубує собі шлях крізь середньовічних ворогів, залишаючи по собі хаос, зламані кістки та зруйновані ілюзії героїзму.',NULL,'https://uakino.best/uploads/mini/poster/2d/17f024d3d7b5d1b7526a77698a2c8d.jpg','22 хв',NULL,NULL,'18+',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(43,32586,'tv-series','Два Ідіоти 1 сезон','Два Ідіоти 1 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:20:21','2026-02-09 15:20:21',NULL,NULL,NULL,NULL,'2026-02-09 15:20:21',2010,NULL,'1080p','Головні герої — Червоний і Синій — два найкращих друга, які живуть разом у квартирі й постійно втягуються в абсолютно ідіотські, часто небезпечні та відверто божевільні ситуації. Червоний — це хаотичний, голосний, безмозкий гедоніст, який обожнює пиво, секс, зброю, вибухи, вечірки та будь-які способи влаштувати катастрофу. Синій — його розумніший (але не набагато) саркастичний друг, який любить рольові ігри, комікси, відеоігри та намагається хоч якось контролювати безумство Червоного, хоча в підсумку завжди пірнає в нього з головою.Кожен епізод триває від двох до п’яти хвилин і являє собою стиснутий вибух чорного гумору, матюків, сексуальних жартів, крові, насильства, пародій на поп-культуру, абсурдних смертей і повного ігнорування будь-якої логіки чи моральних норм. Сюжети можуть бути настільки дикими, як-от змагання, хто більше разів за день помре, спроби вкрасти машину часу, ніндзя-битви, секс з привидами, війна з єнотами, рольові ігри в стилі D&D, які закінчуються справжньою різаниною, або просто безглузді суперечки, що переростають у масове побоїще.',NULL,'https://uakino.best/uploads/mini/serial/ff/1c7892a853f755be37989f52e7a0c4.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(44,7464,'tv-series','Поліція Парадайз 1 сезон','Поліція Парадайз 1 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:20:24','2026-02-09 15:20:24',NULL,NULL,NULL,NULL,'2026-02-09 15:20:24',2018,NULL,'1080p','Кевін Кройфорд все своє життя мріяв стати поліцейським, як і його батько, який очолює управління в невеликому містечку Парадайс. Ось тільки татові не подобається така ідея, навіть більше, він категорично проти цього. Ну, по-перше, він хоче захистити сина від різних небезпек, з якими офіцери стикаються мало не щодня. А, по-друге, він намагається захистити самого себе, оскільки вже давно з Кевіном стався один інцидент, який до цих пір викликає у нього болючі спогади. З іншого боку їх місто відчуває більші фінансові труднощі і може дозволити собі тільки найдешевших робочих. Начальник управління зглянувся над сином і він, нарешті, відправився на свій перший виїзд, навіть не підозрюючи з чим йому доведеться зіткнутися ...',NULL,'https://uakino.best/uploads/mini/serial/20/fd320ca9b1ff22888317c8df01467e.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(45,32559,'movie','Веселий ельф','Веселий ельф',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:20:26','2026-02-09 15:20:26',NULL,NULL,NULL,NULL,'2026-02-09 15:20:26',2005,NULL,'BD-Rip','Головний герой — маленький ельф на ім’я Юбі, який працює в майстерні Санта-Клауса. На відміну від більшості своїх товаришів, Юбі не просто старанно виконує свою роботу — він буквально випромінює радість і непохитну віру в те, що Різдво здатне зробити щасливим абсолютно кожного. Його постійна усмішка, безмежний ентузіазм і дитяча щирість роблять його улюбленцем усіх ельфів… і водночас трохи вибивають з ритму тих, хто звик до більш спокійного темпу підготовки до свята.Одного разу, переглядаючи списки «хороших» і «поганих» дітей, Юбі помічає щось дивне: ціле містечко під назвою Блюзвілль повністю занесене до списку «поганих». Жодна дитина з цього міста не має шансу отримати подарунок. Більше того — саме місто виглядає так, ніби радість покинула його багато років тому: сірі вулиці, похмурі обличчя, постійний дощ і відчуття безнадії, яке пронизує все навколо. Та Юбі не може з цим змиритися. Він вирішує зробити те, на що не наважився б жоден інший ельф: самовільно вирушає до Блюзвілля, щоб особисто повернути місту святковий настрій.',NULL,'https://uakino.best/uploads/mini/poster/cf/136cb946a1f09ce53fc8657150f980.jpg','45 хв',NULL,NULL,'0',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(46,32558,'movie','Брати Санта Клауси','Брати Санта Клауси',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:20:28','2026-02-09 15:20:28',NULL,NULL,NULL,NULL,'2026-02-09 15:20:28',2001,NULL,'BD-Rip','Санта-Клаус має трьох синів-трійнят — Мела, Деріла та Роя, кожен із яких надзвичайно обдарований. Вони успадкували батьківський талант створювати іграшки, поєднуючи його з блискучим науковим розумом і винахідливістю, здатною вразити будь-кого. Та попри всі свої здібності, хлопці сприймають Різдво радше як проєкт і змагання, ніж як свято з глибоким сенсом. Мріючи про спокійний відпочинок і впевнений у тому, що настав час передати справу життя наступному поколінню, Санта оголошує незвичний конкурс: той із синів, хто першим по-справжньому зрозуміє істинне значення Різдва, успадкує сімейну справу.',NULL,'https://uakino.best/uploads/mini/poster/cb/bed17e7da8b9f2132789c2c2ef9a2f.jpg','1 год 00 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(47,32557,'movie','Магічне Різдво Міккі','Магічне Різдво Міккі',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:20:30','2026-02-09 15:20:30',NULL,NULL,NULL,NULL,'2026-02-09 15:20:30',2001,NULL,'BD-Rip','На Різдво Міккі Маус запрошує своїх друзів — Дональда Дака, Ґуфі, Белль, Бембі та багатьох інших улюблених героїв Дісней — зібратися разом і відсвяткувати найжиттєрадісніше свято року. Та святкові плани ледь не псує сильна снігова буря, яка застає всіх зненацька й робить Дональда особливо буркотливим. Утім, друзі не дозволяють негоді зіпсувати настрій і вирішують створити різдвяну атмосферу по-диснеївськи — переглядаючи чарівні різдвяні історії. Класичні мультфільми, сповнені гумору, музики й тепла, поступово повертають святковий дух і розтоплюють навіть серце Дональда, який несподівано стає головною зіркою вечора.',NULL,'https://uakino.best/uploads/mini/poster/09/8509ff0cb3edbf2a45cbdb6d3d4176.jpg','1 год 05 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(48,32556,'movie','Веселі дзвони','Веселі дзвони',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:20:32','2026-02-09 15:20:32',NULL,NULL,NULL,NULL,'2026-02-09 15:20:32',1999,NULL,'BD-Rip','Напередодні різдвяних свят одна малозабезпечена родина з тривогою усвідомлює, що цього року їм не вистачає грошей, аби купити одне одному подарунки. Бажаючи принести близьким бодай трохи радості, батько жертвує єдиною річчю, яка була справді дорогою для всієї сім’ї, і купує подарунки в магазині. Та замість очікуваного щастя свято раптово стає найсумнішим часом року, сповненим мовчазного болю й розчарування. Коли здається, що різдвяне диво неможливе, у справу втручається справжня магія Різдва та доброзичлива допомога Санта-Клауса. Крок за кроком родина відкриває просту, але важливу істину: найцінніші подарунки неможливо купити — вони народжуються з любові, турботи та щирості серця.',NULL,'https://uakino.best/uploads/mini/poster/8d/a953cff8ac4314bb1f17a801e9ad6e.jpg','48 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(49,32555,'tv-series','Капітан Фламінго 1 сезон','Капітан Фламінго 1 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:20:36','2026-02-09 15:20:36',NULL,NULL,NULL,NULL,'2026-02-09 15:20:36',2006,NULL,'BD-Rip','Майло Павелл — хлопчик, який живе звичайним дитячим життям, але щойно хтось опиняється в біді й вимовляє чарівну фразу «Ой-ой, Фламінго!», він миттєво перевтілюється в Капітана Фламінго — самопроголошеного супергероя без жодних справжніх суперздібностей. Озброєний лише яскравим костюмом фламінго та винахідливо використаними іграшками й підручними речами, Капітан Фламінго з ентузіазмом кидається рятувати інших дітей, часто ускладнюючи ситуацію через власну розсіяність і надмірний героїзм. Поруч із ним завжди Лізбет Аманда Сарагоса — подруга й таємний голос розуму, яка непомітно спрямовує Майла, особливо коли він активує свій режим «Пташиний мозок», що насправді є підказками Лізбет у моменти сумнівів. Події мультсеріалу супроводжує всезнаючий оповідач — дотепна пародія на класичних супергеройських нараторів, який не лише коментує те, що відбувається, а й регулярно ламає четверту стіну, звертаючись безпосередньо до глядачів.',NULL,'https://uakino.best/uploads/mini/serial/1d/c6283ea5308fdad5ff96a3cde4172a.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(50,32301,'tv-series','Феріде 1 сезон','Феріде 1 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:20:39','2026-02-09 15:20:39',NULL,NULL,NULL,NULL,'2026-02-09 15:20:39',2025,NULL,'1080p','Феріда — незалежна, прямолінійна та безжально іронічна жінка, яка намагається не втратити оптимізм у світі нудьги, токсичних стосунків, офісного абсурду та сімейних очікувань. Кожен епізод — це кілька коротких, але влучних історій (по 5 хвилин кожна), де Феріда бореться з реальністю: кидає нудного хлопця, мстить ексу через смс, перемагає на корпоративному пейнтболі, намагається знайти «час для себе» і розуміє, що досі не відпустила колишнього. Створено та озвучено Еміром Сагламом. Гумор тут гострий, провокативний, з феміністичним підтекстом і соціальною сатирою на турецьке (і не тільки) суспільство.',NULL,'https://uakino.best/uploads/mini/serial/5e/db9e6c9d50f74f5888690c834d2e16.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(51,32489,'tv-series','Людина-терор 1 сезон','Людина-терор 1 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:20:43','2026-02-09 15:20:43',NULL,NULL,NULL,NULL,'2026-02-09 15:20:43',2026,NULL,'1080p','У центрі сюжету — загадковий чоловік, відомий під псевдонімом Людина-терор / Терор Мен, який володіє надприродною здатністю бачити майбутні катастрофи та трагедії ще до того, як вони стануться. На відміну від класичних супергероїв, його методи запобігання лихам часто виглядають жорстокими, аморальними й навіть терористичними, через що суспільство та влада сприймають його не як рятівника, а як загрозу. Здатність Терор Мена бачити лише «погані кінцівки» перетворює його життя на безперервний ланцюг болісних рішень, адже кожне врятоване майбутнє вимагає від нього особистої втрати, приводить до суспільної ненависті і навіть кривавих фіналів.',NULL,'https://uakino.best/uploads/mini/serial/1d/c97916f07b7b23c86b9ceec55f8c81.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(52,32518,'movie','Місія «Санта»','Місія «Санта»',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:20:44','2026-02-09 15:20:45',NULL,NULL,NULL,NULL,'2026-02-09 15:20:44',2025,NULL,'1080p','Події мультфільму розгортаються на Північному полюсі, де майстерня Санти зазнала радикальних змін: магія, ручна праця й вікові традиції поступилися місцем автоматизації, алгоритмам і холодній ефективності. Схоже, що сам Санта Клаус відійшов від справ, залишивши управління Різдвом новому поколінню технологічно підкованих, але надмірно процесоорієнтованих ельфів. Саме в цю оновлену, майже бездушну систему у свій перший робочий день потрапляє Йойо — добродушний, наївний і щиро захоплений ельф, для якого робота в майстерні Санти була мрією всього життя. Його розчарування сучасною реальністю швидко змінюється справжнім жахом, коли мстивий хакер захоплює контроль над інфраструктурою Північного полюса, паралізуючи виробництво подарунків і ставлячи під загрозу саме існування Різдва. Ситуацію ускладнює те, що ніхто з керівництва навіть не знає, де перебуває Санта і як його знайти, адже система давно навчилася працювати без нього. Єдиним винятком стає Йойо, який упевнений, що його дідусь знає правду про зникнення Санти. Не зважаючи на скепсис колег, Йойо вирушає у відчайдушну подорож разом із цинічною, але не позбавленою серця HR-ельфинею Коко, кумедним оленятком Бiсквітом і пакувальним дроном на ім’я Сноуфлейк. Їхня пригода перетворюється на сповнену гумору, небезпек і тепла місію, у якій технології стикаються з вірою, а прагнення все оптимізувати — з необхідністю відчути справжній сенс Різдва.',NULL,'https://uakino.best/uploads/mini/poster/0e/794e1dd9eaf65f4d7795a725f77c30.jpg','1 год 31 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(53,30380,'tv-series','Сонячні протилежності / Нетутешні 6 сезон','Сонячні протилежності / Нетутешні 6 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:20:48','2026-02-09 15:20:48',NULL,NULL,NULL,NULL,'2026-02-09 15:20:48',2025,NULL,'1080p','У фінальному сезоні Шлорпійці опиняються в епіцентрі хаосу, коли їхній штучний інтелект Айша, раніше надійний помічник у фінансових справах, виходить з-під контролю, руйнуючи систему та загрожуючи існуванню самої Землі. У цей час колишній командир Зарк повертається з темними намірами, активуючи паразитів «Бета Нац», які висмоктують енергію з усієї родини.До того ж Пупа починає проявляти небачену агресію, і Шлорпійці змушені шукати хитромудрі способи приборкати його поведінку — від емоційних фільтрів до інших винахідливих методів, щоб зупинити навислі загрози. Паралельно розгортається сюжет «Стіни», де мініатюрні люди, захоплені прибульцями, будують власне, живе й непередбачуване суспільство.',NULL,'https://uakino.best/uploads/mini/serial/35/e6967b023cfbe88ae4adb51999f9f5.png',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(54,7402,'tv-series','Розчарування 1 сезон','Розчарування 1 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:20:51','2026-02-09 15:20:51',NULL,NULL,NULL,NULL,'2026-02-09 15:20:51',2018,NULL,'1080p','Дія мультсеріалу відбувається в фентезійному світі і бере свій початок в королівстві Дрімленд. У центрі сюжету виявляється принцеса Тіабінія, якій вже порядком набридло нудне і невеселе життя в палаці. До того ж найближчим часом відбудеться її весілля, ось тільки перспектива вийти заміж незрозуміло за кого дівчину зовсім не радує, адже вона мріє про справжнє кохання.Аби не допустити перетворення на заручницю політичних амбіцій батька, Бін тікає з палацу. Разом з \"особистим демоном\" Люцієм, який був подарований дівчині злими магами, а також випадково загулявшим на святі ельфом Елфо, який залишив своїх родичів, принцеса відправляється на пошуки пригод.',NULL,'https://uakino.best/uploads/mini/serial/87/e9c65f748d5e378cd5e75b0a4f6898.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(55,32512,'movie','Мутафуказ','Мутафуказ',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:20:53','2026-02-09 15:20:54',NULL,NULL,NULL,NULL,'2026-02-09 15:20:53',2017,NULL,'1080p','Події відбуваються в Dark Meat City — гіперстилизованому, брудному, кримінальному й абсолютно безнадійному дистопічному місті, яке нагадує найгіршу версію Лос-Анджелеса, де панують вуличні банди, бідність, насильство й повна відсутність перспектив.Головний герой — Анджеліно (або просто Ліно), молодий лузер років двадцяти з невеликим, який виглядає майже як підліток. Він живе в занедбаній квартирі разом зі своїм найкращим другом Вінсом, купою тарганів, яких вважає домашніми улюбленцями, і постійно втрачає роботу кур’єра піци. Життя Анджеліно — суцільне виживання без жодного просвітку. Усе кардинально змінюється після банальної аварії: відволікшись на красиву дівчину на ім’я Луна, він потрапляє під вантажівку на своєму скутері. Фізично він майже не постраждав, але після цього інциденту з ним починають відбуватися дивні речі — кошмари, галюцинації, а головне — він раптом бачить те, що не бачать інші: чорні, хвилясті, потворні тіні, які тягнуться за спиною деяких людей, особливо тих, хто виглядає як агенти в строгих костюмах...',NULL,'https://uakino.best/uploads/mini/poster/42/8ccf32ccf0be8e083283114b2cd450.jpg','1 год 34 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(56,18232,'tv-series','Трансформери: Роботи під прикриттям 4 сезон','Трансформери: Роботи під прикриттям 4 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:20:57','2026-02-09 15:20:57',NULL,NULL,NULL,NULL,'2026-02-09 15:20:57',2017,NULL,'1080p','\"Трансформери: Роботи під прикриттям\" - на всій території галактичного простору панує безтурботна гармонія, що прийшла на зміну багаторічним вселенським баталіям. Жертва шляхетного Прайму виявилася не марною, досі космічні простори осяює потужна енергія, що захищає життя на незліченних планетах від руйнівної дії злих сил. Зайняті мирною працею жителі не підозрюють, що спокій надто крихкий і в будь-який момент може бути порушений стороннім втручанням.Автоботу на ім\'я Бамблі, що колись служив під керівництвом Прайма, приходить термінове повідомлення. У посланні йдеться, що внаслідок аварії на Землю впав зореліт, який перевозив небезпечних злочинців. Десептикони, вирвавшись на волю, тероризують людей, висувають вимоги про помилування своїх побратимів. У справу втручаються могутні роботи вищої раси, які мріють захопити Землю. Бандити, що втекли, повинні стати слухняною зброєю в руках всесильної мафії при здійсненні підступних задумів.Лейтенант Бамблі поспішає допомогти землянам. Він збирає невеликий загін із залізних воїнів. Щоправда, вони надто недосвідчені і не навчені взаємодіяти один з одним. Дінобот задиристий і забіякуватий, мінікон надто активний і неврівноважений, а у юного кадета елітної гвардійської школи поганий характер. Чи вдасться відважному Бамблі перетворити групу новачків на згуртовану команду і врятувати людство від загрози, що нависла?',NULL,'https://uakino.best/uploads/mini/serial/24/0d20243f4034dba8633d8b7c7b42bb.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(57,32505,'tv-series','Світ Вінкс 2 сезон','Світ Вінкс 2 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:21:00','2026-02-09 15:21:00',NULL,NULL,NULL,NULL,'2026-02-09 15:21:00',2017,NULL,'1080p','Після подій першого сезону Блум, Стелла, Флора, Муза, Текна та Айша отримують нове завдання від Духа Світу Мрій. Їм дарують нову силу під назвою Онірікс і відправляють у Неверленд, щоб врятувати цей світ від зла. Головна антагоністка сезону — загадкова та могутня Королева, яка править Неверлендом з позиції сили й темряви. Вінкс дізнаються про її складне минуле й намагаються повернути Королеву до добра, знайшовши її давнього друга — Пітера Пена.Сезон поєднує пригоди на Землі та в магічному світі Неверленді. Дівчата шукають Метта — сина Пітера Пена, стикаються з новими ворогами (серед них з’являються персонажі на кшталт Банші, Крокодилового Чоловіка, Тигрової Лілії, русалок тощо), тренують нові здібності та намагаються захистити талановитих дітей і мрії людства.',NULL,'https://uakino.best/uploads/mini/serial/a4/1d426b0865658911e243c0af7ad27d.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(58,32433,'tv-series','Ші-Ра та могутні принцеси / Ші-Ра та принцеси могутності 3 сезон','Ші-Ра та могутні принцеси / Ші-Ра та принцеси могутності 3 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:21:03','2026-02-09 15:21:03',NULL,NULL,NULL,NULL,'2026-02-09 15:21:03',2019,NULL,'1080p','Третій сезон є досить коротким, але надзвичайно насиченим і поворотним для всієї історії мультсеріалу. Події починаються одразу після фіналу другого сезону, коли в Яскравому Місяці несподівано з’являється Тіньова Ткачка. Вона розкриває небезпечну правду: Гордaк будує портал, який має з’єднати Етерію з рештою імперії Орди. Його запуск може мати катастрофічні наслідки не лише для планети, а й для самої реальності. Адора, Ґліттер і Боу вирушають на пошуки відповідей про Першолюдей і попередню Ші-Ру — Мару, чий прихований сигнал може пояснити справжнє призначення порталу та природу сил, що керують Етерією.Паралельно Катра після поразок і принижень опиняється у Червоній Пустці — жорстокому й хаотичному світі, де вона поступово починає вибудовувати власну владу, віддаляючись від Орди, але не від своєї внутрішньої люті й болю. Саме тут формується новий етап її характеру — більш незалежний, але й ще більш руйнівний. У той самий час Ґордак зближується з Ентраптою, яка допомагає йому вдосконалювати обладунки та портал, і їхній дивний союз відкриває людяніший, уразливий бік антагоніста.',NULL,'https://uakino.best/uploads/mini/serial/25/0db8895292d549d3b57700c7f54aa5.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(59,29408,'tv-series','Зелена змія','Зелена змія',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:21:07','2026-02-09 15:21:07',NULL,NULL,NULL,NULL,'2026-02-09 15:21:07',2021,NULL,'1080p','Біла Змія Бланка та її сестра, Зелена Змія Верта, кидають виклик ченцю Фахаю, але вони зазнають поразки і опиняються запротореними у в\'язниці. Давши урочисту клятву помститися, Зелена Змія знову стикається з фатальними неприємностями, але замість смерті вона неймовірним чином переноситься в антиутопічне місто Асуравілль. Втративши свої магічні сили, Верта пристосовується до життя в незнайомому світі за допомогою жінки на ім\'я Сан і таємничого чоловіка в масці, а також вступає в протистояння з місцевими злочинними угрупованнями...',NULL,'https://uakino.best/uploads/mini/poster/79/0d062a4a703246c07ebdd295c6d801.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(60,7563,'tv-series','Ульотні лунатики 2 сезон','Ульотні лунатики 2 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:21:10','2026-02-09 15:21:10',NULL,NULL,NULL,NULL,'2026-02-09 15:21:10',2006,NULL,'1080p','Шанувальників космічної Фантастики і фентезі чекає продовження мультиплікаційного серіалу про нещасних жителів планети з довгою і складною для вимовлення вимовляють назвою Акметрополіс. Безповітряний простір, звичайно, ніколи не був спокійним місцем, магнітні бурі, падіння зірок і метеоритні дощі тут в порядку речей. Але треба ж було такому статися що один такий «камінчик» звалився на нещасний планетоїд, мало не разнісши його на шматки. Небесне тіло вціліло, але отримало такий струс і сплеск енергії при вибуху, що багато його жителів від малого до великого стали сновидами і отримали дивні таланти.',NULL,'https://uakino.best/uploads/mini/serial/7d/ac29bb5dc7063e475cec9c26212a9e.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(61,32286,'tv-series','Первісний 3 сезон','Первісний 3 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:21:13','2026-02-09 15:21:13',NULL,NULL,NULL,NULL,'2026-02-09 15:21:13',2026,NULL,'1080p','Минають роки після смерті Спіра. Його тіло вже розкладається, коли самотній старий — єдиний вцілілий після жорстокої різанини в селі — знаходить його останки. У пориві помсти він використовує темну магію (зілля, серце ворога, око та інші моторошні інгредієнти), щоб оживити Спіра. Але воскресіння виходить жахливим: Спір повертається без спогадів, без душі, без людяності — просто м’ясна машина для вбивства, керована спочатку заклинанням старого. Його тіло — сіре, звисаюча щелепа, оголені органи, мухи рояться навколо, хода незграбна, рухи механічні. Він не той Спір, якого ми знали: це ходячий труп, який виконує накази, але всередині починають пробиватися крихти спогадів і емоцій.',NULL,'https://uakino.best/uploads/mini/serial/a6/14ab0bcdd9a0fa751ecf715e5fcf34.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(62,32487,'movie','Ліга Справедливості проти Фатальної п\'ятірки','Ліга Справедливості проти Фатальної п\'ятірки',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:21:15','2026-02-09 15:21:15',NULL,NULL,NULL,NULL,'2026-02-09 15:21:15',2019,NULL,'1080p','Анімаційний супергеройський фільм від DC, який повертає класичну команду Ліги Справедливості, виступаючи духовним продовженням стилістики мультсеріалу \"Ліга справедливості: Без меж\". Події розгортаються навколо загрози з майбутнього, коли небезпечна група суперлиходіїв, відома як Фатальна П’ятірка, вирушає назад у часі, щоб змінити хід історії та знищити зародження майбутньої Ліги Справедливості. Центральною фігурою історії стає Старбой — герой із XXXI століття, чия психічна нестабільність і розірвана пам’ять про події майбутнього роблять його водночас ключем до порятунку і джерелом сумнівів для Бетмена, Диво-жінки та Супермена. Протистояння з такими антагоністами, як Манo, Персуейдер, Тарок, Валідус і Емералд Імпрес, поступово переростає з локальної загрози у масштабний конфлікт, де на кону стоїть сама ідея героїзму.',NULL,'https://uakino.best/uploads/mini/poster/cb/6412ba386ec9815672337037838b7e.jpg','1 год 17 хв',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(63,31666,'tv-series','Розкрадачка гробниць: Легенда Лари Крофт 2 сезон','Розкрадачка гробниць: Легенда Лари Крофт 2 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:21:19','2026-02-09 15:21:19',NULL,NULL,NULL,NULL,'2026-02-09 15:21:19',2025,NULL,'1080p','Досвідчена, але все ще внутрішньо зранена минулим, Лара Крофт знову вирушає у небезпечну подорож світом, де стародавні легенди тісно переплітаються з сучасними змовами. Цього разу вона разом зі своєю близькою подругою Сем Нішімурою розслідує викрадення містичних африканських масок оріша — артефактів, що, за легендами, пов’язані з божественними силами та здатні змінити хід історії. Полювання за реліквіями швидко перетворюється на смертельно небезпечне протистояння, адже за ними також стоїть впливовий і загадковий мільярдер, готовий піти на все заради розширення меж своєї влади.',NULL,'https://uakino.best/uploads/mini/serial/49/6c5c542e08acab15ef1ae8c7695f53.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(64,32479,'movie','Юні титани, вперед!','Юні титани, вперед!',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:21:20','2026-02-09 15:21:21',NULL,NULL,NULL,NULL,'2026-02-09 15:21:20',2018,NULL,'1080p','У цьому яскравому, самоіронічному й динамічному анімаційному фільмі Юні Титани раптом усвідомлюють прикру істину: у світі супергероїв кожен поважний герой уже має власний гучний кінохіт, і лише вони залишаються осторонь великого екрану. Особливо болісно це сприймає Робін, фактичний лідер команди, який понад усе прагне довести, що він не просто «напарник без плаща», а справжній герой, гідний головної ролі. Переконаний, що шлях до слави лежить через Голлівуд, Робін надихає Рейвен, Старфайр, Біст Боя й Кіборга вирушити до Тінселтауна, де, озброєні безглуздими ідеями, щирим ентузіазмом і запальними піснями, Титани намагаються привернути увагу наймоднішого кінорежисера. Проте їхня мрія про кінообкладинки швидко перетворюється на хаос, коли на горизонті з’являється небезпечний суперлиходій з маніакальним планом захоплення Землі, який навмисно спрямовує команду хибним шляхом.',NULL,'https://uakino.best/uploads/mini/poster/53/d1baae85a8150221221605d0d72214.jpg','1 год 24 хв',NULL,NULL,'6',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(65,31633,'tv-series','Мисливці на тролів 2 сезон','Мисливці на тролів 2 сезон',NULL,NULL,NULL,NULL,NULL,1,'2026-02-09 15:21:24','2026-02-09 15:21:24',NULL,NULL,NULL,NULL,'2026-02-09 15:21:24',2017,NULL,'1080p','У цьому сезоні ставки значно зростають. Після подій фіналу першого сезону Джим вирушає до Темних земель, аби врятувати Клер та її молодшого брата Енґуса, чим запускає ланцюг нових небезпек. Тим часом у Аркадії його друзі Тобі, Блінкi та Ааарраг намагаються тримати місто в безпеці, борючись із все сильнішими ворогами, яких надсилають Ґунмар і його армія. Упродовж сезону команда стикається зі зрадою, стародавніми пророцтвами та новими союзниками, поступово усвідомлюючи, що війна між світлом і тінню охоплює не лише світ тролів, а й людський. Другий сезон значно розширює міфологію \"Казок Аркадії\", зосереджуючись на більш темних сюжетних лініях, глибшому розвитку персонажів і підготовці до масштабних подій, що розгорнуться в майбутніх сюжетах.',NULL,'https://uakino.best/uploads/mini/serial/3f/3ec4b13f41c54b6b1dd6f1ad345231.jpg',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,NULL,NULL,0),(66,32476,'movie','Снігова королева','Снігова королева',NULL,NULL,NULL,NULL,NULL,0,'2026-02-09 15:21:26','2026-02-09 15:21:26',NULL,NULL,NULL,NULL,'2026-02-09 15:21:26',2025,NULL,'1080p','Сюжет розповідає про юну дівчинку Герду, яка вирушає в небезпечну подорож на північ, щоб врятувати свого найкращого друга Кая, якого викрала зла Снігова королева і тримає полоненим у своєму крижаному палаці далеко на півночі Норвегії, в регіоні Фіннмарк. Під час подорожі Герда долає численні випробування, заводить нових друзів серед людей, птахів, тварин і навіть відьом, не підозрюючи, що її таємно переслідує сама королева та її учень-чортеня Людвіг. Мультфільм є сучасною адаптацією класичного однойменного казкового оповідання Ганса Крістіана Андерсена, але з норвезьким колоритом та акцентом на північні ландшафти Фіннмарку.',NULL,'https://